const TimeInput = ({ value, onChange, onFocus, onBlurExtra, className = '', title = '', placeholder = '', inputRef = null, onKeyDown }) => {
  const handleChange = (e) => {
    let v = e.target.value.replace(/[^0-9:]/g, '');
    if (v.length === 2 && !v.includes(':')) v = v + ':';
    if (v.length > 5) v = v.slice(0, 5);
    onChange(v);
  };
  const handleBlur = (e) => {
    let v = e.target.value.trim();
    if (/^\d{4}$/.test(v)) v = v.slice(0, 2) + ':' + v.slice(2);
    if (!/^\d{2}:\d{2}$/.test(v)) { onChange(v); onBlurExtra?.(); return; }
    const [h, min] = v.split(':').map(Number);
    // 24:00 = ?먯젙(?곸뾽 醫낅즺) ?덉슜, 洹???h>23 遺덊뿀
    if (h > 24 || min > 59 || (h === 24 && min > 0)) { onChange(''); onBlurExtra?.(); return; }
    onChange(v);
    onBlurExtra?.();
  };
  return (
    <input
      ref={inputRef}
      type="text"
      inputMode="numeric"
      draggable={false}
      data-no-drag="true"
      value={value}
      onChange={handleChange}
      onFocus={onFocus}
      onBlur={handleBlur}
      onKeyDown={onKeyDown}
      onPointerDown={(e) => e.stopPropagation()}
      onMouseDown={(e) => e.stopPropagation()}
      onTouchStart={(e) => e.stopPropagation()}
      onDragStart={(e) => {
        e.preventDefault();
        e.stopPropagation();
      }}
      placeholder={placeholder}
      maxLength={5}
      title={title}
      className={className}
    />
  );
};
const buildBusinessQuickEditSegments = (businessRaw = {}) => {
  const business = normalizeBusiness(businessRaw || {});
  const segments = [];
  if (business.open || business.close) segments.push({ fieldKey: 'open', label: `?댁쁺 ${business.open || '--:--'} - ${business.close || '--:--'}` });
  if (business.breakStart || business.breakEnd) segments.push({ fieldKey: 'breakStart', label: `?댁떇 ${business.breakStart || '--:--'} - ${business.breakEnd || '--:--'}` });
  if (business.lastOrder || business.entryClose) segments.push({ fieldKey: 'lastOrder', label: `留덇컧 ${business.lastOrder || business.entryClose || '--:--'}` });
  if (business.closedDays?.length) segments.push({ fieldKey: 'closedDays', label: `?대Т : ${formatClosedDaysSummary(business.closedDays)}` });
  return segments;
};
