      if (item.types?.includes('ship')) {
        const shipTimeline = getShipTimeline(item);
        prevEndMinutes = shipTimeline.disembark;
        item.duration = Math.max(0, shipTimeline.disembark - timeToMinutes(item.time || '00:00'));
